import React from 'react';

import type { SharedCatalogProposalSubmitChange } from './SharedCatalogProposalModal';

import { SharedCatalogProposalTrigger } from './SharedCatalogProposalTrigger';

import styles from '../../styles/erpPage.module.css';



export interface SharedCatalogFormActionsProps {

  testIdPrefix: string;

  catalogKind: string;

  usageActive: boolean;

  canRequest: boolean;

  row: { code: string; name?: string; isActive?: boolean; isReadOnly?: boolean; scope?: string } | null;

  currentValues?: Record<string, unknown>;

  onSubmitUsage: (note?: string) => Promise<void>;

  onSubmitChange: (entityKey: string, submit: SharedCatalogProposalSubmitChange) => Promise<void>;

}



/** Workflow 2 — nút «Đề xuất» trong modal edit (§8.18). */

export const SharedCatalogFormActions: React.FC<SharedCatalogFormActionsProps> = ({

  testIdPrefix,

  catalogKind,

  usageActive,

  canRequest,

  row,

  currentValues,

  onSubmitUsage,

  onSubmitChange,

}) => {

  if (!canRequest || !usageActive || !row) return null;



  const isShared = row.isReadOnly || row.scope === 'Shared' || row.scope === 'System';

  const modes = isShared ? (['change'] as const) : (['usage', 'change'] as const);

  const defaultChangeAction = isShared ? 'Update' : 'Create';



  return (

    <div className={styles.sharedCatalogFormActions} data-testid={`${testIdPrefix}-shared-form-actions`}>

      <SharedCatalogProposalTrigger

        testIdPrefix={testIdPrefix}

        catalogKind={catalogKind}

        label="Đề xuất"

        modes={[...modes]}

        context="item"

        entityKey={row.code}

        entityLabel={row.name ?? row.code}

        defaultChangeAction={defaultChangeAction}

        currentValues={currentValues ?? { name: row.name, isActive: row.isActive }}

        onSubmitUsage={onSubmitUsage}

        onSubmitChange={submit => onSubmitChange(row.code, submit)}

      />

    </div>

  );

};

